import{_ as i,o as r,c as a,a3 as t}from"./chunks/framework.CRbjHCyB.js";const p=JSON.parse('{"title":"Index","description":"","frontmatter":{},"headers":[],"relativePath":"clice/design/index.md","filePath":"en/clice/design/index.md"}'),d={name:"clice/design/index.md"};function n(o,e,s,l,c,h){return r(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="index" tabindex="-1">Index <a class="header-anchor" href="#index" aria-label="Permalink to &quot;Index&quot;">​</a></h1><p>clice maintains a persistent symbol index for cross-TU queries — find references, call hierarchy, workspace symbol search, and more. The index is built in the background and stored on disk using FlatBuffers serialization.</p><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><h3 id="data-layers" tabindex="-1">Data Layers <a class="header-anchor" href="#data-layers" aria-label="Permalink to &quot;Data Layers&quot;">​</a></h3><ul><li><p><strong>TUIndex</strong> (<code>src/index/tu_index.h</code>) — per-translation-unit symbol data produced by <code>SemanticVisitor</code> during compilation. Contains symbol hashes, occurrence locations, and relations (definition, reference, base, derived, caller/callee). This is an ephemeral output merged into the persistent stores below.</p></li><li><p><strong>ProjectIndex</strong> (<code>src/index/project_index.h</code>) — global cross-TU symbol index. Maps symbol hashes to their definition locations, names, kinds, and aggregated relations across the entire project.</p></li><li><p><strong>MergedIndex</strong> (<code>src/index/merged_index.h</code>) — per-file shards that merge header contexts. A single header may be indexed through multiple host sources; the merged index reconciles these into a unified view.</p></li></ul><h3 id="indexer-src-server-compiler-indexer-h" tabindex="-1">Indexer (<code>src/server/compiler/indexer.h</code>) <a class="header-anchor" href="#indexer-src-server-compiler-indexer-h" aria-label="Permalink to &quot;Indexer (`src/server/compiler/indexer.h`)&quot;">​</a></h3><p>The <code>Indexer</code> class is the query + scheduling layer. It holds no index data itself — persistent data lives in <code>Workspace</code> (ProjectIndex + MergedIndex shards), and per-file unsaved-buffer data lives in <code>Session</code> (OpenFileIndex).</p><p>Responsibilities:</p><ul><li>Cross-file navigation queries (definition, references, hierarchy)</li><li>Symbol search (<code>workspace/symbol</code>)</li><li>Background indexing scheduling with idle timeout and deduplication</li><li>Merging TUIndex results into persistent stores</li><li>Disk save/load of index shards</li></ul><h2 id="background-indexing" tabindex="-1">Background Indexing <a class="header-anchor" href="#background-indexing" aria-label="Permalink to &quot;Background Indexing&quot;">​</a></h2><p>After a file is compiled, its TUIndex is merged into the project-wide index. Background indexing runs during idle periods (configurable via <code>idle_timeout_ms</code>, default 3s):</p><ol><li>Files are enqueued when opened, saved, or when their dependencies change.</li><li>An idle timer deduplicates rapid changes — indexing starts only after the timeout.</li><li>Tasks are dispatched to stateless workers with configurable concurrency.</li><li>Indexing is paused during latency-sensitive requests (completion, signature help, formatting) via <code>ScopedPause</code>.</li><li>Progress is reported to the client via LSP <code>$/progress</code> notifications.</li></ol><h2 id="queries" tabindex="-1">Queries <a class="header-anchor" href="#queries" aria-label="Permalink to &quot;Queries&quot;">​</a></h2><p>The indexer supports these cross-TU queries:</p><table tabindex="0"><thead><tr><th>Query</th><th>Method</th></tr></thead><tbody><tr><td>Go to definition</td><td><code>query_relations(path, pos, Definition)</code></td></tr><tr><td>Find references</td><td><code>query_relations(path, pos, Reference)</code></td></tr><tr><td>Call hierarchy (incoming)</td><td><code>find_incoming_calls(hash)</code></td></tr><tr><td>Call hierarchy (outgoing)</td><td><code>find_outgoing_calls(hash)</code></td></tr><tr><td>Type hierarchy</td><td><code>resolve_hierarchy_item()</code></td></tr><tr><td>Workspace symbol</td><td>Search across ProjectIndex</td></tr></tbody></table><p>For open files with unsaved changes, queries check the Session&#39;s OpenFileIndex first, then fall back to the persisted MergedIndex.</p><h2 id="serialization" tabindex="-1">Serialization <a class="header-anchor" href="#serialization" aria-label="Permalink to &quot;Serialization&quot;">​</a></h2><p>Index data is serialized with <a href="https://flatbuffers.dev/" target="_blank" rel="noreferrer">FlatBuffers</a> (<code>src/index/schema.fbs</code>) for:</p><ul><li>Zero-copy deserialization — index shards can be memory-mapped from disk</li><li>Compact binary format — smaller than JSON/protobuf for symbol data</li><li>Efficient partial reads — only load the shards needed for a query</li></ul><h2 id="symbol-identification" tabindex="-1">Symbol Identification <a class="header-anchor" href="#symbol-identification" aria-label="Permalink to &quot;Symbol Identification&quot;">​</a></h2><p>Symbols are identified by a 64-bit hash (<code>SymbolHash</code>) derived from Clang&#39;s USR (Unified Symbol Resolution) string. USR generation (<code>src/index/usr_generation.cpp</code>) produces a canonical identifier for each symbol that is stable across TUs.</p>',21)])])}const f=i(d,[["render",n]]);export{p as __pageData,f as default};
